import React, { useState, useEffect } from 'react';

function ApiExample() {
  // 投稿一覧の状態
  const [posts, setPosts] = useState([]);
  const [loadingPosts, setLoadingPosts] = useState(true);
  const [error, setError] = useState(null);

  // 新規投稿の状態
  const [newPost, setNewPost] = useState({ title: '', body: '' });
  const [submitting, setSubmitting] = useState(false);
  const [submitSuccess, setSubmitSuccess] = useState(false);

  // コンポーネントマウント時に投稿一覧を取得
  useEffect(() => {
    fetchPosts();
  }, []);

  // 投稿一覧を取得する関数
  const fetchPosts = async () => {
    try {
      setLoadingPosts(true);

      // JSONPlaceholderの無料APIを使用
      const response = await fetch('https://jsonplaceholder.typicode.com/posts?_limit=5');

      if (!response.ok) {
        throw new Error(`APIエラー: ${response.status}`);
      }

      const data = await response.json();
      setPosts(data);
      setError(null);
    } catch (err) {
      setError(err.message);
      setPosts([]);
    } finally {
      setLoadingPosts(false);
    }
  };

  // 入力フォームの変更ハンドラー
  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setNewPost(prev => ({
      ...prev,
      [name]: value
    }));
  };

  // 新規投稿の送信ハンドラー
  const handleSubmit = async (e) => {
    e.preventDefault();

    // バリデーション
    if (!newPost.title.trim() || !newPost.body.trim()) {
      setError('タイトルと本文は必須です');
      return;
    }

    try {
      setSubmitting(true);
      setError(null);

      // POSTリクエストの送信
      const response = await fetch('https://jsonplaceholder.typicode.com/posts', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({
          title: newPost.title,
          body: newPost.body,
          userId: 1  // ダミーユーザーID
        })
      });

      if (!response.ok) {
        throw new Error(`APIエラー: ${response.status}`);
      }

      const createdPost = await response.json();
      console.log('作成された投稿:', createdPost);

      // 成功メッセージを表示
      setSubmitSuccess(true);

      // 投稿リストを更新（JSONPlaceholderは実際には更新されないため、手動で追加）
      setPosts(prev => [createdPost, ...prev]);

      // フォームをリセット
      setNewPost({ title: '', body: '' });

      // 3秒後に成功メッセージを非表示
      setTimeout(() => {
        setSubmitSuccess(false);
      }, 3000);

    } catch (err) {
      setError(err.message);
    } finally {
      setSubmitting(false);
    }
  };

  // スタイル定義
  const styles = {
    container: {
      maxWidth: '800px',
      margin: '0 auto',
      padding: '20px',
      fontFamily: 'Arial, sans-serif'
    },
    header: {
      borderBottom: '2px solid #3498db',
      paddingBottom: '10px',
      marginBottom: '20px',
      color: '#2c3e50'
    },
    form: {
      marginBottom: '30px',
      padding: '20px',
      backgroundColor: '#f7f7f7',
      borderRadius: '8px'
    },
    formGroup: {
      marginBottom: '15px'
    },
    label: {
      display: 'block',
      marginBottom: '5px',
      fontWeight: 'bold'
    },
    input: {
      width: '100%',
      padding: '8px',
      fontSize: '16px',
      borderRadius: '4px',
      border: '1px solid #ddd'
    },
    textarea: {
      width: '100%',
      padding: '8px',
      fontSize: '16px',
      borderRadius: '4px',
      border: '1px solid #ddd',
      minHeight: '100px'
    },
    submitButton: {
      backgroundColor: '#3498db',
      color: 'white',
      border: 'none',
      padding: '10px 15px',
      borderRadius: '4px',
      cursor: 'pointer',
      fontSize: '16px'
    },
    disabledButton: {
      backgroundColor: '#95a5a6',
      cursor: 'not-allowed'
    },
    errorMessage: {
      backgroundColor: '#f8d7da',
      color: '#721c24',
      padding: '10px',
      borderRadius: '4px',
      marginBottom: '20px'
    },
    successMessage: {
      backgroundColor: '#d4edda',
      color: '#155724',
      padding: '10px',
      borderRadius: '4px',
      marginBottom: '20px'
    },
    loadingIndicator: {
      textAlign: 'center',
      padding: '20px'
    },
    postList: {
      listStyle: 'none',
      padding: 0
    },
    postItem: {
      border: '1px solid #ddd',
      borderRadius: '8px',
      padding: '15px',
      marginBottom: '15px'
    },
    postTitle: {
      margin: '0 0 10px 0',
      color: '#3498db'
    },
    postBody: {
      margin: 0,
      color: '#555'
    }
  };

  return (
    <div style={styles.container}>
      <h1 style={styles.header}>APIと連携するReactアプリ</h1>

      {/* エラーメッセージ */}
      {error && (
        <div style={styles.errorMessage}>
          {error}
        </div>
      )}

      {/* 成功メッセージ */}
      {submitSuccess && (
        <div style={styles.successMessage}>
          投稿が正常に作成されました！
        </div>
      )}

      {/* 新規投稿フォーム */}
      <div style={styles.form}>
        <h2>新規投稿を作成</h2>
        <form onSubmit={handleSubmit}>
          <div style={styles.formGroup}>
            <label style={styles.label} htmlFor="title">タイトル:</label>
            <input
              style={styles.input}
              type="text"
              id="title"
              name="title"
              value={newPost.title}
              onChange={handleInputChange}
              disabled={submitting}
            />
          </div>

          <div style={styles.formGroup}>
            <label style={styles.label} htmlFor="body">内容:</label>
            <textarea
              style={styles.textarea}
              id="body"
              name="body"
              value={newPost.body}
              onChange={handleInputChange}
              disabled={submitting}
            />
          </div>

          <button
            style={{
              ...styles.submitButton,
              ...(submitting ? styles.disabledButton : {})
            }}
            type="submit"
            disabled={submitting}
          >
            {submitting ? '送信中...' : '投稿する'}
          </button>
        </form>
      </div>

      {/* 投稿一覧 */}
      <div>
        <h2>投稿一覧</h2>

        {loadingPosts ? (
          <div style={styles.loadingIndicator}>読み込み中...</div>
        ) : posts.length > 0 ? (
          <ul style={styles.postList}>
            {posts.map(post => (
              <li key={post.id} style={styles.postItem}>
                <h3 style={styles.postTitle}>{post.title}</h3>
                <p style={styles.postBody}>{post.body}</p>
              </li>
            ))}
          </ul>
        ) : (
          <p>投稿がありません</p>
        )}
      </div>
    </div>
  );
